// paged_attention_f16_kv_f16: paged attention

marmot_error_t
marmot_metal_paged_attention_f16_kv_f16_exec(const void *device_ctx, const marmot_kernel_args_paged_attention_t *args) {
    if (args == nullptr) {
        marmot_set_error(MARMOT_ERROR_INVALID_ARGUMENT, "Kernel args not provided");
        return MARMOT_ERROR_INVALID_ARGUMENT;
    }
    marmot_paged_attention_desc_t desc = marmot_paged_attention_desc_default();
    desc.token_count = args->token_count;
    desc.layer_idx = args->layer_idx;
    desc.num_q_heads = args->num_q_heads;
    desc.num_kv_heads = args->num_kv_heads;
    desc.head_dim = args->head_dim;
    desc.block_size = args->block_size;
    desc.scale = args->scale;
    desc.token_meta = args->token_meta;
    desc.q = args->q;
    desc.k_new = args->k_new;
    desc.v_new = args->v_new;
    desc.kv_k = args->kv_k;
    desc.kv_v = args->kv_v;
    desc.block_table = args->block_table;
    desc.out = args->out;
    marmot_paged_attention_kv_scale_ext_t scale_ext = marmot_paged_attention_kv_scale_ext_default();
    if (args->kv_k_scale != nullptr || args->kv_v_scale != nullptr) {
        scale_ext.kv_k_scale = args->kv_k_scale;
        scale_ext.kv_v_scale = args->kv_v_scale;
        desc.pnext = &scale_ext;
    }
    return metal_paged_attention_impl(device_ctx, &desc);
}

